import React, { useState, useEffect } from 'react';
import { adminService } from '../services/adminService';
import { Search, RefreshCw, Trash2, Plus, Edit2, Shield, User } from 'lucide-react';

const PERMISSIONS = [
  { id: 'overview', label: 'Overview (Dashboard)' },
  { id: 'notifications', label: 'Notifications' },
  { id: 'chats', label: 'Chats' },
  { id: 'cities', label: 'Cities' },
  { id: 'orders', label: 'Orders' },
  { id: 'customOrders', label: 'Custom Orders' },
  { id: 'rides', label: 'Rides & Parcels' },
  { id: 'products', label: 'Products' },
  { id: 'customers', label: 'Customers' },
  { id: 'riders', label: 'Riders' },
  { id: 'shops', label: 'Shops' },
  { id: 'banners', label: 'Banners' },
  { id: 'paymentMethods', label: 'Payment Methods' },
  { id: 'walletDeposits', label: 'Wallet Deposits' },
  { id: 'settings', label: 'Settings' },
];

const SubAdmins = () => {
  const [admins, setAdmins] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [editingAdmin, setEditingAdmin] = useState(null);
  const [formData, setFormData] = useState({
    name: '', email: '', password: '', phone: '', city: '', permissions: [] });

  const fetchAdmins = async () => {
    setLoading(true);
    try {
      const data = await adminService.getAdmins();
      setAdmins(data);
    } catch (error) {
      alert('Failed to fetch admins');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAdmins();
  }, []);

  const handleCreate = async () => {
    if (!formData.name || !formData.email || !formData.password || !formData.phone || !formData.city) {
      alert('Please fill all required fields');
      return;
    }

    try {
      if (editingAdmin) {
        await adminService.updateSubAdmin(editingAdmin._id, formData);
      } else {
        await adminService.createSubAdmin(formData);
      }
      setShowModal(false);
      resetForm();
      fetchAdmins();
    } catch (error) {
      alert('Failed to save sub-admin');
    }
  };

  const handleEdit = (admin) => {
    setEditingAdmin(admin);
    setFormData({
      name: admin.name,
      email: admin.email,
      password: '', // Don't pre-fill password
      phone: admin.phone,
      city: admin.city,
      permissions: admin.permissions || [],
    });
    setShowModal(true);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this sub-admin?')) {
      try {
        await adminService.deleteSubAdmin(id);
        setAdmins(admins.filter(a => a._id !== id));
      } catch (error) {
        alert('Failed to delete sub-admin');
      }
    }
  };

  const resetForm = () => {
    setEditingAdmin(null);
    setFormData({ name: '', email: '', password: '', phone: '', city: '', permissions: [] });
  };

  const handlePermissionToggle = (permId) => {
    setFormData(prev => ({
      ...prev,
      permissions: prev.permissions.includes(permId)
        ? prev.permissions.filter(p => p !== permId)
        : [...prev.permissions, permId]
    }));
  };

  const filteredAdmins = admins.filter(admin =>
    admin.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    admin.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="content-area animate-fade-in">
      <div className="section-header">
        <div>
          <h2>Admin Management</h2>
          <p className="section-subtitle">Manage main admin and sub-admins with permissions</p>
        </div>
        <div style={{ display: 'flex', gap: '0.75rem' }}>
          <button className="primary-btn icon-text-btn" onClick={fetchAdmins}>
            <RefreshCw size={18} className={loading ? 'animate-spin' : ''} />
            Refresh
          </button>
          <button className="primary-btn icon-text-btn" onClick={() => {
            resetForm();
            setShowModal(true);
          }}>
            <Plus size={18} />
            Add Sub Admin
          </button>
        </div>
      </div>

      <div className="search-bar-container glass-panel">
        <Search size={20} className="search-icon" />
        <input
          type="text"
          placeholder="Search by name or email..."
          className="search-input"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="glass-panel" style={{ marginTop: '2rem' }}>
        {loading ? (
          <div className="table-loader">Loading admins...</div>
        ) : (
          <table className="admin-table">
            <thead>
              <tr>
                <th>User</th>
                <th>Contact Info</th>
                <th>Role</th>
                <th>Permissions</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredAdmins.map((admin) => (
                <tr key={admin._id}>
                  <td>
                    <div className="user-info-cell">
                      <div className="user-avatar customer-avatar">
                        <img
                          src={admin.image || `https://ui-avatars.com/api/?name=${encodeURIComponent(admin.name)}&background=random`}
                          alt={admin.name}
                          style={{ width: '100%', height: '100%', borderRadius: '12px', objectFit: 'cover' }}
                        />
                      </div>
                      <div className="user-name">
                        {admin.name}
                      </div>
                    </div>
                  </td>
                  <td>
                    <div className="contact-info">
                      <div className="info-item">
                        <span>{admin.email}</span>
                      </div>
                      <div className="info-item">
                        <span>{admin.phone}</span>
                      </div>
                    </div>
                  </td>
                  <td>
                    <span className="status-badge" style={{
                      backgroundColor: admin.role === 'admin' ? '#f59e0b' : '#10b981',
                      color: 'white',
                      fontSize: '12px',
                      padding: '4px 10px',
                      textTransform: 'capitalize'
                    }}>
                      {admin.role}
                    </span>
                  </td>
                  <td>
                    {admin.role === 'admin' ? (
                      <span style={{ color: 'var(--text-muted)', fontSize: '12px' }}>Full Access</span>
                    ) : (
                      <div style={{ display: 'flex', flexWrap: 'wrap', gap: '4px' }}>
                        {(admin.permissions || []).slice(0, 4).map(p => {
                          const permLabel = PERMISSIONS.find(pr => pr.id === p)?.label || p;
                          return (
                            <span
                              key={p}
                              style={{
                                backgroundColor: 'rgba(59,130,246,0.1)',
                                color: 'var(--accent-primary)',
                                padding: '2px 8px',
                                borderRadius: '6px',
                                fontSize: '10px'
                              }}
                            >
                              {permLabel}
                            </span>
                          );
                        })}
                        {admin.permissions?.length > 4 && (
                          <span style={{ fontSize: '10px', color: 'var(--text-muted)' }}>
                            +{admin.permissions.length - 4} more
                          </span>
                        )}
                      </div>
                    )}
                  </td>
                  <td>
                    {admin.role === 'sub-admin' ? (
                      <div style={{ display: 'flex', gap: '8px' }}>
                        <button
                          className="action-btn verify"
                          onClick={() => handleEdit(admin)}
                          title="Edit Sub Admin"
                        >
                          <Edit2 size={18} />
                        </button>
                        <button
                          className="action-btn delete"
                          onClick={() => handleDelete(admin._id)}
                          title="Delete Sub Admin"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                    ) : (
                      <span style={{ color: 'var(--text-muted)', fontSize: '12px' }}>Main Admin</span>
                    )}
                  </td>
                </tr>
              ))}
              {filteredAdmins.length === 0 && (
                <tr>
                  <td colSpan="5" className="empty-table-msg">No admins found.</td>
                </tr>
              )}
            </tbody>
          </table>
        )}
      </div>

      {/* Modal for create/edit */}
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal glass-panel" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '600px', maxHeight: '90vh', overflowY: 'auto' }}>
            <div className="modal-header">
              <h3>{editingAdmin ? 'Edit Sub Admin' : 'Add Sub Admin'}</h3>
              <button onClick={() => setShowModal(false)} style={{
                background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer', fontSize: '20px' }}>&times;</button>
            </div>
            <div className="modal-content" style={{ padding: '1.5rem', display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                  <label style={{ color: 'var(--text-muted)', fontSize: '0.875rem' }}>Name *</label>
                  <input
                    type="text"
                    value={formData.name}
                    onChange={(e) => setFormData(p => ({ ...p, name: e.target.value }))}
                    style={{
                      width: '100%',
                      padding: '0.75rem 1rem',
                      borderRadius: '8px',
                      border: '1px solid rgba(255,255,255,0.1)',
                      background: 'var(--surface-color)',
                      color: 'var(--text-primary)',
                      fontSize: '0.875rem'
                    }}
                    placeholder="Full Name"
                  />
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                  <label style={{ color: 'var(--text-muted)', fontSize: '0.875rem' }}>Email *</label>
                  <input
                    type="email"
                    value={formData.email}
                    onChange={(e) => setFormData(p => ({ ...p, email: e.target.value }))}
                    style={{
                      width: '100%',
                      padding: '0.75rem 1rem',
                      borderRadius: '8px',
                      border: '1px solid rgba(255,255,255,0.1)',
                      background: 'var(--surface-color)',
                      color: 'var(--text-primary)',
                      fontSize: '0.875rem'
                    }}
                    placeholder="Email Address"
                  />
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                  <label style={{ color: 'var(--text-muted)', fontSize: '0.875rem' }}>Password {!editingAdmin && '*'}</label>
                  <input
                    type="password"
                    value={formData.password}
                    onChange={(e) => setFormData(p => ({ ...p, password: e.target.value }))}
                    style={{
                      width: '100%',
                      padding: '0.75rem 1rem',
                      borderRadius: '8px',
                      border: '1px solid rgba(255,255,255,0.1)',
                      background: 'var(--surface-color)',
                      color: 'var(--text-primary)',
                      fontSize: '0.875rem'
                    }}
                    placeholder={editingAdmin ? 'Leave blank to keep current password' : 'Password'}
                  />
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                  <label style={{ color: 'var(--text-muted)', fontSize: '0.875rem' }}>Phone *</label>
                  <input
                    type="text"
                    value={formData.phone}
                    onChange={(e) => setFormData(p => ({ ...p, phone: e.target.value }))}
                    style={{
                      width: '100%',
                      padding: '0.75rem 1rem',
                      borderRadius: '8px',
                      border: '1px solid rgba(255,255,255,0.1)',
                      background: 'var(--surface-color)',
                      color: 'var(--text-primary)',
                      fontSize: '0.875rem'
                    }}
                    placeholder="Phone Number"
                  />
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                  <label style={{ color: 'var(--text-muted)', fontSize: '0.875rem' }}>City *</label>
                  <input
                    type="text"
                    value={formData.city}
                    onChange={(e) => setFormData(p => ({ ...p, city: e.target.value }))}
                    style={{
                      width: '100%',
                      padding: '0.75rem 1rem',
                      borderRadius: '8px',
                      border: '1px solid rgba(255,255,255,0.1)',
                      background: 'var(--surface-color)',
                      color: 'var(--text-primary)',
                      fontSize: '0.875rem'
                    }}
                    placeholder="City"
                  />
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <Shield size={16} color="var(--accent-primary)" />
                    <span style={{ fontWeight: '600', fontSize: '0.875rem' }}>Permissions</span>
                  </div>
                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '0.75rem' }}>
                    {PERMISSIONS.map(perm => (
                      <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.875rem', cursor: 'pointer' }} key={perm.id}>
                        <input
                          type="checkbox"
                          checked={formData.permissions.includes(perm.id)}
                          onChange={() => handlePermissionToggle(perm.id)}
                          style={{ width: '16px', height: '16px' }}
                        />
                        <span>{perm.label}</span>
                      </label>
                    ))}
                  </div>
                </div>
              </div>
              <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '0.75rem' }}>
                <button
                  className="secondary-btn"
                  onClick={() => setShowModal(false)}
                >
                  Cancel
                </button>
                <button
                  className="primary-btn"
                  onClick={handleCreate}
                >
                  {editingAdmin ? 'Update Sub Admin' : 'Create Sub Admin'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default SubAdmins;
